import json
import re

# Access the result from storage
credit_card_businesses = locals()['var_functions.query_db:5']

# If it's a file path, read it
if isinstance(credit_card_businesses, str):
    with open(credit_card_businesses, 'r') as f:
        credit_card_businesses = json.load(f)

# Function to extract categories from description
def extract_categories(description):
    if not description:
        return []

    patterns = [
        r'fields of ([^\.]+)',
        r'categories of ([^\.]+)',
        r'services in ([^\.]+)',
        r'range of services including ([^\.]+)',
        r'offers a ([^\.,]+)',
        r'array of ([^\.]+)',
        r'category of \'([^\']+)\''
    ]

    categories = []
    for pattern in patterns:
        matches = re.findall(pattern, description, re.IGNORECASE)
        for match in matches:
            parts = match.split(',')
            for part in parts:
                part = part.strip()
                if part.startswith('and '):
                    part = part[4:].strip()

                part = part.replace('"', '').replace("'", "").strip()

                if part and len(part) > 2 and not part.lower().startswith('including'):
                    if ' and ' in part:
                        subparts = part.split(' and ')
                        for subpart in subparts:
                            subpart = subpart.strip()
                            if subpart and len(subpart) > 2:
                                categories.append(subpart)
                    else:
                        categories.append(part)

    return categories

# Extract business data
business_data = []
for business in credit_card_businesses:
    business_id = business.get('business_id', '')
    description = business.get('description', '')
    numeric_id = business_id.replace('businessid_', '') if business_id else ''

    categories = extract_categories(description)

    business_data.append({
        'business_id': business_id,
        'numeric_id': numeric_id,
        'categories': categories
    })

# Count categories
category_counts = {}
for business in business_data:
    for category in business['categories']:
        category_counts[category] = category_counts.get(category, 0) + 1

# Sort by count
sorted_categories = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)

top_category = sorted_categories[0] if sorted_categories else (None, 0)

print('__RESULT__:')
print(json.dumps({
    'top_category': top_category,
    'total_businesses': len(business_data),
    'distinct_categories': len(category_counts)
}))

